                    unsigned char *bp, unsigned char **out, size_t *outsize)
{
    /* TODO(lode): make more efficient (add more bits at once). */
    unsigned i;
    for (i = 0; i < length; i++)
    {
        unsigned bit = (symbol >> i) & 1;
        if (*bp == 0)
            ZOPFLI_APPEND_DATA(0, out, outsize);
        (*out)[*outsize - 1] |= bit << *bp;
        *bp = (*bp + 1) & 7;
    }
}

